package com.careeros.watchlist.infrastructure; import com.careeros.watchlist.domain.*; import org.springframework.data.domain.*; import org.springframework.data.jpa.repository.*; import org.springframework.stereotype.Repository; import java.util.*;
interface SpringDataWatchlistRepository extends JpaRepository<Watchlist,UUID>{} @Repository class WatchlistRepositoryAdapter implements WatchlistRepository{private final SpringDataWatchlistRepository r;WatchlistRepositoryAdapter(SpringDataWatchlistRepository r){this.r=r;}public Watchlist save(Watchlist w){return r.save(w);}public Optional<Watchlist> findById(UUID id){return r.findById(id);}public Page<Watchlist> findAll(Pageable p){return r.findAll(p);}public List<Watchlist> findAll(){return r.findAll();}public void deleteById(UUID id){r.deleteById(id);}}
